<?php
declare(strict_types=1);
function vp3_reel_card(array $clip):string{
 $uuid=vp3_e((string)($clip['publication_uuid']??''));$title=vp3_e((string)($clip['title']??''));$caption=vp3_e((string)($clip['caption']??''));$creator=vp3_e((string)($clip['creator_name']??'VP3 Creator'));$creatorSlug=urlencode((string)($clip['creator_slug']??''));$creatorUuid=vp3_e((string)($clip['creator_uuid']??''));$show=vp3_e((string)($clip['show_title']??'VP3 Show'));$showSlug=urlencode((string)($clip['show_slug']??''));$showUuid=vp3_e((string)($clip['show_uuid']??''));$media=vp3_e(vp3_public_https_url((string)($clip['source_media_url']??'')));$poster=vp3_e(vp3_public_https_url((string)($clip['poster_url']??'')));$destination=vp3_e(vp3_public_https_url((string)($clip['destination_url']??''),'#'));$liked=!empty($clip['liked']);$saved=!empty($clip['saved']);$follows=!empty($clip['follows_creator']);$followsShow=!empty($clip['follows_show']);$comments=(int)($clip['comment_count']??0);
 return '<article class="reel" data-reel data-publication-uuid="'.$uuid.'" data-creator-uuid="'.$creatorUuid.'" data-show-uuid="'.$showUuid.'"><div class="reel-stage">'.($media?'<video playsinline loop muted preload="metadata" poster="'.$poster.'"><source src="'.$media.'"></video>':'').($poster?'<img class="reel-poster" src="'.$poster.'" alt="">':'<div class="reel-placeholder"><span>VP3</span></div>').'<button class="reel-center-play" type="button" aria-label="Play or pause">▶</button><div class="reel-gradient"></div><div class="reel-copy"><a class="reel-creator" href="creator.php?slug='.$creatorSlug.'">'.$creator.' <small>✓</small></a><h2>'.$title.'</h2><p>'.$caption.'</p><a class="reel-show" href="show.php?slug='.$showSlug.'">'.$show.' →</a><a class="reel-destination button small" href="'.$destination.'" target="_blank" rel="noopener">Enter the full experience</a></div><aside class="reel-actions"><button type="button" data-action="like" class="'.($liked?'active':'').'"><span>♡</span><small>Like</small></button><button type="button" data-comments-button><span>◌</span><small>'.$comments.'</small></button><button type="button" data-action="save" class="'.($saved?'active':'').'"><span>▣</span><small>Save</small></button><button type="button" data-action="follow_creator" class="'.($follows?'active':'').'"><span>＋</span><small>Creator</small></button><button type="button" data-action="follow_show" class="'.($followsShow?'active':'').'"><span>◎</span><small>Show</small></button><button type="button" data-mute-button><span>⊘</span><small>Mute</small></button><button type="button" data-action="share"><span>↗</span><small>Share</small></button><button type="button" data-action="report"><span>!</span><small>Report</small></button></aside><div class="reel-progress"><i></i></div></div></article>';
}
